#include <stdio.h>
#include <string.h>

int main() {
    char order[8][9];
    for (int i = 0; i < 8; i++) {
        scanf("%s", order[i]);
    }

    int allBlack = 1;
    int count = 0;

    for (int i = 0; i < 8; i++) {
        if (strcmp(order[i], "BBBBBBBB") == 0) {
            count += 1;
        } else {
            allBlack = 0;
        }
    }

    for (int i = 0; i < 8; i++) {
        count += 1;
        for (int ii = 0; ii < 8; ii++) {
            if (order[ii][i] == 'W') {
                count -= 1;
                break;
            }
        }
    }

    if (count == 16) {
        printf("8\n");
    } else {
        printf("%d\n", count);
    }

    return 0;
}
